use std::collections::HashMap;

fn cube(x: i64) -> i64 {
    x * x * x
}

fn solve(n: i64) -> Vec<i64> {
    let mut sum_counts: HashMap<i64, i32> = HashMap::new();

    // Determine A_max: a^3 <= N/2
    // We use floating point math for bounds estimation.
    let n_half = (n as f64) / 2.0;
    let mut a_max = n_half.powf(1.0 / 3.0).floor() as i64;

    // Robustly adjust A_max due to potential floating point errors
    // Ensure a_max is the largest integer such that cube(a_max) <= n/2
    while cube(a_max + 1) <= n / 2 {
        a_max += 1;
    }
    while cube(a_max) > n / 2 && a_max >= 1 {
        a_max -= 1;
    }

    if a_max < 1 {
        return Vec::new();
    }

    // Iterate over 'a'
    for a in 1..=a_max {
        let a_cubed = cube(a);

        let n_minus_a3 = n - a_cubed;

        // Determine B_max: b^3 <= N - a^3
        let b_max_float = (n_minus_a3 as f64).powf(1.0 / 3.0).floor() as i64;
        let mut b_max = b_max_float;

        // Robustly adjust B_max
        // Ensure b_max is the largest integer such that cube(b_max) <= n_minus_a3
        while cube(b_max + 1) <= n_minus_a3 {
            b_max += 1;
        }
        while cube(b_max) > n_minus_a3 {
            b_max -= 1;
        }

        // Iterate over 'b', starting from 'a' (since a <= b)
        for b in a..=b_max {
            let b_cubed = cube(b);
            let current_sum = a_cubed + b_cubed;

            // Update count
            *sum_counts.entry(current_sum).or_insert(0) += 1;
        }
    }

    // Collect results: numbers with count >= 2
    let mut good_numbers: Vec<i64> = Vec::new();
    for (sum, count) in sum_counts {
        if count >= 2 {
            good_numbers.push(sum);
        }
    }

    // Sort the results in ascending order
    good_numbers.sort_unstable();

    good_numbers
}

