function solve(n) {
    // Map to store the count of ways each sum (x) can be represented as a^3 + b^3
    const sumCounts = new Map();

    // Determine the maximum possible value for 'a'.
    // Since a <= b, we must have a^3 + b^3 >= 2*a^3.
    // 2*a^3 <= n => a^3 <= n/2
    // We use Math.cbrt for cube root calculation.

