    const a_max_float = Math.cbrt(n / 2);
    const a_max = Math.floor(a_max_float);

    for (let a = 1; a <= a_max; a++) {
        const a_cubed = a * a * a;

        // 'b' starts from 'a' since we require a <= b.
        // b must satisfy a^3 + b^3 <= n, so b^3 <= n - a^3.
        const n_minus_a3 = n - a_cubed;
        if (n_minus_a3 < a_cubed) {
             // If n - a^3 < a^3, then b^3 < a^3, meaning b < a. Since b starts at a, 
             // we can stop checking this 'a' if we reach a point where the maximum b is less than a.
             // However, the loop condition for b handles this naturally.
        }

        // Calculate the maximum integer b such that b^3 <= n - a^3
        const b_max_float = Math.cbrt(n_minus_a3);
        const b_max = Math.floor(b_max_float);

        for (let b = a; b <= b_max; b++) {
            const b_cubed = b * b * b;
            const currentSum = a_cubed + b_cubed;

            // Although b_max calculation should prevent currentSum > n, 
            // a final check ensures robustness against floating point inaccuracies if they were large, 
            // but here we rely on the bounds calculation.
            if (currentSum > n) {
                // Should not happen if b_max is correct, but good practice.
                break; 
            }

            // Update count
            const currentCount = sumCounts.get(currentSum) || 0;
            sumCounts.set(currentSum, currentCount + 1);
        }
    }

    const goodNumbers = [];
    // Collect all numbers that have a count of 2 or more
    for (const [sum, count] of sumCounts.entries()) {
        if (count >= 2) {
            goodNumbers.push(sum);
        }
    }

    // Return the results sorted in ascending order
    goodNumbers.sort((a, b) => a - b);

    return goodNumbers;
}
